# PATCH-UPDATE.ps1 — Updates all scene files on your Windows machine
# Double-click this file OR run it in PowerShell
Write-Host ""
Write-Host "  =========================================="
Write-Host "   RETURN OF JUDAH - Applying Claude's Updates"
Write-Host "  =========================================="
Write-Host ""

$base = Split-Path -Parent $MyInvocation.MyCommand.Path

# Create scenes folder
New-Item -ItemType Directory -Force -Path "$base\src\components\scenes" | Out-Null

Write-Host "  Updating files..."


$content = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(''))
$dir = Split-Path "$base\src\components\KenBurns.jsx"
New-Item -ItemType Directory -Force -Path $dir | Out-Null
Set-Content -Path "$base\src\components\KenBurns.jsx" -Value $content -Encoding UTF8
Write-Host "  OK: src/components/KenBurns.jsx"

